const body = $input.first().json.body;
const transcript = body.transcript || '';
const filename = body.filename || 'manual_input.txt';

// Write transcript to temp file
const fs = require('fs');
const path = `/data/project/dataset/demo/${filename}`;
fs.mkdirSync('/data/project/dataset/demo', { recursive: true });
fs.writeFileSync(path, transcript);

return [{ json: { path, filename, length: transcript.length } }];

const stdout = $input.first().json.stdout;
// Extract account ID from pipeline output
const match = stdout.match(/Pipeline A complete: ([\w-]+)/);
const accountId = match ? match[1] : 'unknown';

// Read generated files
const fs = require('fs');
const basePath = `/data/project/outputs/accounts/${accountId}/v1`;
let memo = {}, spec = {};
try { memo = JSON.parse(fs.readFileSync(`${basePath}/account_memo.json`, 'utf8')); } catch(e) {}
try { spec = JSON.parse(fs.readFileSync(`${basePath}/agent_spec.json`, 'utf8')); } catch(e) {}

return [{ json: { account_id: accountId, memo, spec, status: 'v1_created' } }];
